import { useFormik } from "formik";
import { LeagueTable } from "../../objects/league-table";
import { PostLeagueTableResult } from "../../services/league-table-service";

const AdminResult = ()  =>
{
    const formik = useFormik({
        initialValues :{
                team: 0,                 
                season: 6,
                won : 0,
                lost: 0,
                drawn : 0,
                glsFor : 0,
                glsA : 0
                },
        onSubmit : values => {
            const leageTable : LeagueTable = {
                id : 1,
                achieveablePoints: 0,
                gd : 0,
                pld : 0,
                points : 0,
                teamName : "",
                drawn : values.drawn,                
                glsA : values.glsA,
                glsFor: values.glsFor,
                lost : values.lost,                
                seasonId : values.season,
                teamId : values.team,
                won : values.won
            }
            PostLeagueTableResult(leageTable).then(formik.resetForm);
        }
    });

    return(

        <>
        <div>hi</div>
        <div>           
            <form onSubmit={formik.handleSubmit} >
                 Team Id<input type="text" {...formik.getFieldProps("team")}/> 
                 Season Id<input type="text" {...formik.getFieldProps("season")}/> 
                 Won<input type="text" {...formik.getFieldProps("won")}/> 
                 Lost<input type="text" {...formik.getFieldProps("lost")}/> 
                 Drawn<input type="text" {...formik.getFieldProps("drawn")}/> 
                 Gls For<input type="text" {...formik.getFieldProps("glsFor")}/> 
                 Gls A<input type="text" {...formik.getFieldProps("glsA")}/> 
                 <button type="submit">Go</button>  
            </form>            
        </div>
        </>
    );
}

export default AdminResult;
